800	    fn stringIsNumber(str: String, offset: *usize) bool {
801	        const start = offset.*;
802	        var i = start;
803	
804	        var @"+" = false;
805	        var @"-" = false;
806	        var e = false;
807	        var dot = false;
808	
809	        var base: enum { dec, hex, oct } = .dec;
810	
811	        next: switch (str.charAt(i)) {
812	            '.' => {
813	                if (dot or base != .dec) {
814	                    offset.* = i;
815	                    return false;
816	                }
817	                dot = true;
818	                i += 1;
819	                if (i < str.length()) {
820	                    continue :next str.charAt(i);
821	                }
822	                return true;
823	            },
824	
825	            '+' => {
826	                if (@"+") {
827	                    offset.* = i;
828	                    return false;
829	                }
