**File**: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775498803409-zk5qry/packages/bun-types/bun.d.ts`

Each namespace is exposed as a `namespace` on the `Bun` global object:

```typescript
namespace Bun {
  namespace TOML {
    export function parse(input: string): object;
  }

  namespace JSONC {
    export function parse(input: string): unknown;
  }

  namespace JSON5 {
    export function parse(input: string): unknown;
    export function stringify(input: unknown, replacer?: undefined | null, space?: string | number): string | undefined;
  }

  namespace YAML {
    export function parse(input: string): unknown;
    export function stringify(input: unknown, replacer?: undefined | null, space?: string | number): string;
  }
}
