#### JSON5 & YAML
Both have custom `exprToJS()` functions that recursively convert:

```zig
fn exprToJS(expr: Expr, global: *jsc.JSGlobalObject) bun.JSError!jsc.JSValue {
    switch (expr.data) {
        .e_null => return .null,
        .e_boolean => return .jsBoolean(boolean.value),
        .e_number => return .jsNumber(number.value),
        .e_string => return str.toJS(bun.default_allocator, global),
        .e_array => {
            var js_arr = try JSValue.createEmptyArray(global, arr.items.len);
            for (arr.slice(), 0..) |item, i| {
                const value = try exprToJS(item, global);
                try js_arr.putIndex(global, @intCast(i), value);
            }
            return js_arr;
        },
        .e_object => {
            var js_obj = JSValue.createEmptyObject(global, obj.properties.len);
            for (obj.properties.slice()) |prop| {
                const key_js = try exprToJS(prop.key.?, global);
                const value_js = try exprToJS(prop.value.?, global);
                const key_str = try key_js.toBunString(global);
                defer key_str.deref();
                try js_obj.putMayBeIndex(global, &key_str, value_js);
            }
            return js_obj;
        },
        else => return .js_undefined,
    }
}
```

