pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argumentsAsArray(1)[0];

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
    defer arena.deinit();

    const input: jsc.Node.BlobOrStringOrBuffer =
        try jsc.Node.BlobOrStringOrBuffer.fromJS(global, arena.allocator(), input_value) orelse input: {
        var str = try input_value.toBunString(global);
        defer str.deref();
        break :input .{ .string_or_buffer = .{ .string = str.toSlice(arena.allocator()) } };
    };
    defer input.deinit();

    const data = input.slice();
    const result = JSValue.createEmptyObject(global, 0);
    var current_section = result;

    var pos: usize = 0;
    while (pos < data.len) {
        const line_start = pos;
        while (pos < data.len and data[pos] != '\n' and data[pos] != '\r') {
            pos += 1;
        }
        const raw_line = data[line_start..pos];

        // Skip past line endings (\r\n or \n or \r)
        if (pos < data.len and data[pos] == '\r') pos += 1;
        if (pos < data.len and data[pos] == '\n') pos += 1;

        const line = trim(raw_line);

        // Skip empty lines and comment lines
        if (line.len == 0 or line[0] == ';' or line[0] == '#') continue;

        // Section header: [section_name]
        if (line[0] == '[') {
            if (std.mem.indexOfScalar(u8, line, ']')) |close| {
                const section_name = trim(line[1..close]);
                if (section_name.len > 0) {
                    const section_obj = JSValue.createEmptyObject(global, 0);
                    var key_str = bun.String.cloneUTF8(section_name);
                    defer key_str.deref();
                    try result.putMayBeIndex(global, &key_str, section_obj);
                    current_section = section_obj;
                }
            }
            continue;
        }

        // Key-value pair: key = value or key : value
        const sep_idx = findSeparator(line) orelse continue;
        const key = trim(line[0..sep_idx]);
        if (key.len == 0) continue;
        const raw_value = trim(line[sep_idx + 1 ..]);

        const value_js = try parseValue(global, raw_value);
        var key_str = bun.String.cloneUTF8(key);
        defer key_str.deref();
        try current_section.putMayBeIndex(global, &key_str, value_js);
    }

    return result;
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argumentsAsArray(1)[0];

    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
        return .js_undefined;
    }

    if (value.isNull() or !value.isObject() or value.isArray()) {
        return global.throw("INI.stringify expects a plain object", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    var wrote_anything = false;

    // First pass: write top-level non-object properties (global keys)
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) continue;
            if (isSectionValue(iter.value)) continue;

            builder.append(.string, prop_name);
            builder.append(.latin1, " = ");
            try appendValue(&builder, global, iter.value);
            builder.append(.lchar, '\n');
            wrote_anything = true;
        }
    }

    // Second pass: write sections (object-valued properties)
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) continue;
            if (!isSectionValue(iter.value)) continue;

            if (wrote_anything) {
                builder.append(.lchar, '\n');
            }
            wrote_anything = true;

            builder.append(.lchar, '[');
            builder.append(.string, prop_name);
            builder.append(.latin1, "]\n");

            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                global,
                try iter.value.toObject(global),
            );
            defer section_iter.deinit();

            while (try section_iter.next()) |section_prop_name| {
                if (section_iter.value.isUndefined() or section_iter.value.isSymbol() or section_iter.value.isFunction()) continue;

                builder.append(.string, section_prop_name);
                builder.append(.latin1, " = ");
                try appendValue(&builder, global, section_iter.value);
                builder.append(.lchar, '\n');
            }
        }
    }

    return builder.toString(global);
}

fn isSectionValue(value: jsc.JSValue) bool {
    return value.isObject() and !value.isArray() and !value.isNull() and !value.isFunction();
}

fn appendValue(builder: *wtf.StringBuilder, global: *jsc.JSGlobalObject, value: jsc.JSValue) bun.JSError!void {
    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        return;
    }
    if (value.isNull()) {
        builder.append(.latin1, "null");
        return;
    }
    if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
        return;
    }
    // For strings and anything else, convert to string representation
    const str = try value.toBunString(global);
    defer str.deref();
    builder.append(.string, str);
}

fn parseValue(global: *jsc.JSGlobalObject, raw: []const u8) bun.JSError!jsc.JSValue {
    if (raw.len == 0) {
        return try bun.String.createUTF8ForJS(global, "");
    }

    // Handle quoted strings: strip surrounding quotes
    if (raw.len >= 2) {
        if ((raw[0] == '"' and raw[raw.len - 1] == '"') or
            (raw[0] == '\'' and raw[raw.len - 1] == '\''))
        {
            return try bun.String.createUTF8ForJS(global, raw[1 .. raw.len - 1]);
        }
    }

    // Boolean values (case-insensitive)
    if (eqlIgnoreCase(raw, "true") or
        eqlIgnoreCase(raw, "yes") or
        eqlIgnoreCase(raw, "on"))
    {
        return .jsBoolean(true);
    }
    if (eqlIgnoreCase(raw, "false") or
        eqlIgnoreCase(raw, "no") or
        eqlIgnoreCase(raw, "off"))
    {
        return .jsBoolean(false);
    }

    // Null
    if (eqlIgnoreCase(raw, "null") or eqlIgnoreCase(raw, "none")) {
        return .null;
    }

    // Try numeric parsing (only if it starts with a digit, sign, or dot)
    if (raw[0] == '-' or raw[0] == '+' or raw[0] == '.' or (raw[0] >= '0' and raw[0] <= '9')) {
        if (std.fmt.parseFloat(f64, raw)) |num| {
            return .jsNumber(num);
        } else |_| {}
    }

    // Default: return as string
    return try bun.String.createUTF8ForJS(global, raw);
}

fn findSeparator(line: []const u8) ?usize {
    for (line, 0..) |c, i| {
        if (c == '=' or c == ':') return i;
    }
    return null;
}

fn trim(s: []const u8) []const u8 {
    var start: usize = 0;
    while (start < s.len and (s[start] == ' ' or s[start] == '\t')) start += 1;
    var end: usize = s.len;
    while (end > start and (s[end - 1] == ' ' or s[end - 1] == '\t')) end -= 1;
    return s[start..end];
}

fn eqlIgnoreCase(a: []const u8, b: []const u8) bool {
    if (a.len != b.len) return false;
    for (a, b) |ca, cb| {
        const la: u8 = if (ca >= 'A' and ca <= 'Z') ca | 0x20 else ca;
        const lb: u8 = if (cb >= 'A' and cb <= 'Z') cb | 0x20 else cb;
        if (la != lb) return false;
    }
    return true;
}

