import { describe, expect, test } from "bun:test";

describe("Bun.INI", () => {
  test("parse is a function", () => {
    expect(typeof Bun.INI.parse).toBe("function");
  });

  test("stringify is a function", () => {
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  describe("parse", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.parse("key1 = value1\nkey2 = value2");
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("sections as nested objects", () => {
      const result = Bun.INI.parse(`
key1 = value1

[section1]
key2 = value2
key3 = value3

[section2]
key4 = value4
`);
      expect(result).toEqual({
        key1: "value1",
        section1: {
          key2: "value2",
          key3: "value3",
        },
        section2: {
          key4: "value4",
        },
      });
    });

    test("semicolon comments are ignored", () => {
      const result = Bun.INI.parse(`
; This is a comment
key1 = value1
; Another comment
key2 = value2
`);
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("hash comments are ignored", () => {
      const result = Bun.INI.parse(`
# This is a comment
key1 = value1
# Another comment
key2 = value2
`);
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("empty lines are ignored", () => {
      const result = Bun.INI.parse(`

key1 = value1


key2 = value2

`);
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("boolean values (case-insensitive)", () => {
      const result = Bun.INI.parse(`
a = true
b = false
c = True
d = False
e = TRUE
f = FALSE
g = yes
h = no
i = on
j = off
`);
      expect(result).toEqual({
        a: true,
        b: false,
        c: true,
        d: false,
        e: true,
        f: false,
        g: true,
        h: false,
        i: true,
        j: false,
      });
    });

    test("null values", () => {
      const result = Bun.INI.parse(`
a = null
b = none
c = Null
d = None
`);
      expect(result).toEqual({
        a: null,
        b: null,
        c: null,
        d: null,
      });
    });

    test("numeric values", () => {
      const result = Bun.INI.parse(`
int = 42
negative = -7
float = 3.14
zero = 0
`);
      expect(result).toEqual({
        int: 42,
        negative: -7,
        float: 3.14,
        zero: 0,
      });
    });

    test("quoted string values have quotes stripped", () => {
      const result = Bun.INI.parse(`
double = "hello world"
single = 'hello world'
`);
      expect(result).toEqual({
        double: "hello world",
        single: "hello world",
      });
    });

    test("quoted strings preserve values that would otherwise be parsed", () => {
      const result = Bun.INI.parse(`
a = "true"
b = "42"
c = "null"
`);
      expect(result).toEqual({
        a: "true",
        b: "42",
        c: "null",
      });
    });

    test("colon as separator", () => {
      const result = Bun.INI.parse("key1 : value1\nkey2 : value2");
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("whitespace trimming around keys and values", () => {
      const result = Bun.INI.parse("  key1  =  value1  \n  key2  =  value2  ");
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("empty value returns empty string", () => {
      const result = Bun.INI.parse("key =");
      expect(result).toEqual({
        key: "",
      });
    });

    test("handles CRLF line endings", () => {
      const result = Bun.INI.parse("key1 = value1\r\nkey2 = value2\r\n");
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("handles CR-only line endings", () => {
      const result = Bun.INI.parse("key1 = value1\rkey2 = value2\r");
      expect(result).toEqual({
        key1: "value1",
        key2: "value2",
      });
    });

    test("empty input returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("comments-only input returns empty object", () => {
      expect(Bun.INI.parse("; just a comment\n# another one")).toEqual({});
    });

    test("equals sign in value is preserved", () => {
      const result = Bun.INI.parse("key = a=b=c");
      expect(result).toEqual({
        key: "a=b=c",
      });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse(`
[server]
host = localhost
port = 8080

[database]
host = db.example.com
port = 5432
name = mydb
`);
      expect(result).toEqual({
        server: {
          host: "localhost",
          port: 8080,
        },
        database: {
          host: "db.example.com",
          port: 5432,
          name: "mydb",
        },
      });
    });

    test("throws on undefined/null input", () => {
      expect(() => Bun.INI.parse(undefined as any)).toThrow();
      expect(() => Bun.INI.parse(null as any)).toThrow();
    });
  });

  describe("stringify", () => {
    test("basic key-value pairs", () => {
      const result = Bun.INI.stringify({
        key1: "value1",
        key2: "value2",
      });
      expect(result).toBe("key1 = value1\nkey2 = value2\n");
    });

    test("sections", () => {
      const result = Bun.INI.stringify({
        section1: {
          key1: "value1",
        },
      });
      expect(result).toBe("[section1]\nkey1 = value1\n");
    });

    test("mixed global keys and sections", () => {
      const result = Bun.INI.stringify({
        name: "my-app",
        database: {
          host: "localhost",
          port: 5432,
        },
      });
      expect(result).toBe("name = my-app\n\n[database]\nhost = localhost\nport = 5432\n");
    });

    test("boolean values", () => {
      const result = Bun.INI.stringify({
        enabled: true,
        disabled: false,
      });
      expect(result).toBe("enabled = true\ndisabled = false\n");
    });

    test("null values", () => {
      const result = Bun.INI.stringify({
        empty: null,
      });
      expect(result).toBe("empty = null\n");
    });

    test("numeric values", () => {
      const result = Bun.INI.stringify({
        count: 42,
        ratio: 3.14,
      });
      expect(result).toBe("count = 42\nratio = 3.14\n");
    });

    test("empty object returns empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("returns undefined for non-object input", () => {
      expect(Bun.INI.stringify(undefined as any)).toBeUndefined();
    });

    test("throws for null input", () => {
      expect(() => Bun.INI.stringify(null as any)).toThrow();
    });

    test("throws for array input", () => {
      expect(() => Bun.INI.stringify([] as any)).toThrow();
    });

    test("multiple sections with no global keys", () => {
      const result = Bun.INI.stringify({
        server: {
          host: "localhost",
        },
        database: {
          host: "db.local",
        },
      });
      expect(result).toBe("[server]\nhost = localhost\n\n[database]\nhost = db.local\n");
    });
  });

  describe("roundtrip", () => {
    test("parse then stringify preserves structure", () => {
      const ini = `name = my-app\nversion = 1\n\n[database]\nhost = localhost\nport = 5432\n`;
      const parsed = Bun.INI.parse(ini);
      const stringified = Bun.INI.stringify(parsed as any);
      const reparsed = Bun.INI.parse(stringified);
      expect(reparsed).toEqual(parsed);
    });

    test("stringify then parse preserves values", () => {
      const obj = {
        name: "test",
        debug: true,
        server: {
          host: "0.0.0.0",
          port: 3000,
        },
      };
      const ini = Bun.INI.stringify(obj);
      const parsed = Bun.INI.parse(ini);
      expect(parsed).toEqual(obj);
    });
  });
});

