57	while (<IN>) {
58	    chomp;
59	    s/^\s+//;
60	    next if /^\#|^$/; # Comment or blank line. Do nothing.
61	    if (/^\@begin/ && !$inside) {
62	        if (/^\@begin\s*([:_\w]+)\s*\d*\s*$/) {
63	            $inside = 1;
64	            $name = $1;
65	        } else {
66	            print STDERR "WARNING: \@begin without table name, skipping $_\n";
67	        }
68	    } elsif (/^\@end\s*$/ && $inside) {
69	        output();
70	
71	        @keys = ();
72	        @attrs = ();
73	        @values = ();
74	        $includeBuiltin = 0;
75	
76	        $inside = 0;
77	    } elsif (/^(\S+)\s*(\S+)\s*([\w\|]*)\s*(\w*)\s*(\w*)\s*$/ && $inside) {
78	        my $key = $1;
79	        my $val = $2;
80	        my $att = $3;
81	        my $param = $4;
82	        my $intrinsic = $5;
83	
84	        push(@keys, $key);
85	        push(@attrs, length($att) > 0 ? $att : "None");
86	
87	        if ($val eq "JSBuiltin") {
88	            $includeBuiltin = 1;
89	        }
90	
91	        if ($att =~ m/Function/) {
92	            push(@values, { "type" => "PropertyAttribute::Function", "function" => $val, "params" => (length($param) ? $param : ""), "intrinsic" => (length($intrinsic) ? $intrinsic : "NoIntrinsic") });
93	            #printf STDERR "WARNING: Number of arguments missing for $key/$val\n" if (length($param) == 0);
94	        } elsif ($att =~ m/CellProperty/) {
95	            my $property = $val;
96	            push(@values, { "type" => "PropertyAttribute::CellProperty", "property" => $property });
97	        } elsif ($att =~ m/ClassStructure/) {
98	            my $property = $val;
99	            push(@values, { "type" => "PropertyAttribute::ClassStructure", "property" => $property });
100	        } elsif ($att =~ m/PropertyCallback/) {
101	            my $cback = $val;
102	            push(@values, { "type" => "PropertyAttribute::PropertyCallback", "cback" => $cback });
103	        } elsif ($att =~ m/ConstantInteger/) {
104	            my $value = $val;
105	            push(@values, { "type" => "PropertyAttribute::ConstantInteger", "value" => $value });
106	        } elsif (length($att)) {
107	            my $get = $val;
108	            my $put = "0";
109	            my $type = "PropertyAttribute::Property";
110	            if ($att =~ m/Builtin/) {
111	                $type = "PropertyAttribute::BuiltinAccessor";
112	            }
113	            if (!($att =~ m/ReadOnly/)) {
114	                $put = "set" . jsc_ucfirst($val);
115	            }
116	            $hasSetter = "true";
117	            push(@values, { "type" => $type, "get" => $get, "put" => $put });
118	        } else {
119	            push(@values, { "type" => "Lexer", "value" => $val });
120	        }
121	    } elsif ($inside) {
122	        die "invalid data {" . $_ . "}";
123	    }
124	}
