128	sub jsc_ucfirst($)
129	{
130	    my ($value) = @_;
131	
132	    if ($value =~ /js/) {
133	        $value =~ s/js/JS/;
134	        return $value;
135	    }
136	
137	    return ucfirst($value);
138	}
