141	sub ceilingToPowerOf2
142	{
143	    my ($perfectHashSize) = @_;
144	
145	    my $powerOf2 = 1;
146	    while ($perfectHashSize > $powerOf2) {
147	        $powerOf2 <<= 1;
148	    }
149	
150	    return $powerOf2;
151	}
152	
153	sub calcPerfectHashSize()
154	{
155	tableSizeLoop:
156	    for ($perfectHashSize = ceilingToPowerOf2(scalar @keys); ; $perfectHashSize += $perfectHashSize) {
157	        if ($perfectHashSize > 2**15) {
158	            die "The hash size is far too big. This should not be reached.";
159	        }
160	        my @table = ();
161	        foreach my $key (@keys) {
162	            my $h = hashValue($key) % $perfectHashSize;
163	            next tableSizeLoop if $table[$h];
164	            $table[$h] = 1;
165	        }
166	        last;
167	    }
168	}
169	
170	sub calcCompactHashSize()
171	{
172	    my $compactHashSize = ceilingToPowerOf2(2 * @keys);
173	    $compactHashSizeMask = $compactHashSize - 1;
174	    $compactSize = $compactHashSize;
175	    my $collisions = 0;
176	    my $maxdepth = 0;
177	    my $i = 0;
178	    foreach my $key (@keys) {
179	        my $depth = 0;
180	        my $h = hashValue($key) % $compactHashSize;
181	        while (defined($table[$h])) {
182	            if ($compactSize > 1000) {
183	                die "The hash size is far too big. This should not be reached.";
184	            }
185	            if ($depth > 100) {
186	                die "The depth is far too big. This should not be reached.";
187	            }
188	            if (defined($links[$h])) {
189	                $h = $links[$h];
190	                $depth++;
191	            } else {
192	                $collisions++;
193	                $links[$h] = $compactSize;
194	                $h = $compactSize;
195	                $compactSize++;
196	            }
197	        }
198	        $table[$h] = $i;
199	        $i++;
200	        $maxdepth = $depth if ($depth > $maxdepth);
201	    }
202	}
