204	sub maskTop8BitsAndAvoidZero($) {
205	    my ($value) = @_;
206	
207	    $value &= $mask32;
208	
209	    # Save 8 bits for StringImpl to use as flags.
210	    $value &= 0xffffff;
211	
212	    # This avoids ever returning a hash code of 0, since that is used to
213	    # signal "hash not computed yet". Setting the high bit maintains
214	    # reasonable fidelity to a hash code of 0 because it is likely to yield
215	    # exactly 0 when hash lookup masks out the high bits.
216	    $value = (0x80000000 >> 8) if ($value == 0);
217	
218	    return $value;
219	}
