221	sub uint64_add($$) {
222	    my ($a, $b) = @_;
223	    my $sum = $a + $b;
224	    return $sum & $mask64;
225	}
226	
227	sub uint64_multi($$) {
228	    my ($a, $b) = @_;
229	    my $product = $a * $b;
230	    return $product & $mask64;
231	}
