233	sub wymum($$) {
234	    my ($A, $B) = @_;
235	
236	    my $ha = $A >> 32;
237	    my $hb = $B >> 32;
238	    my $la = $A & $mask32;
239	    my $lb = $B & $mask32;
240	    my $hi;
241	    my $lo;
242	    my $rh = uint64_multi($ha, $hb);
243	    my $rm0 = uint64_multi($ha, $lb);
244	    my $rm1 = uint64_multi($hb, $la);
245	    my $rl = uint64_multi($la, $lb);
246	    my $t = uint64_add($rl, ($rm0 << 32));
247	    my $c = int($t < $rl);
248	
249	    $lo = uint64_add($t, ($rm1 << 32));
250	    $c += int($lo < $t);
251	    $hi = uint64_add($rh, uint64_add(($rm0 >> 32), uint64_add(($rm1 >> 32), $c)));
252	
253	    return ($lo, $hi);
254	};
255	
256	sub wymix($$) {
257	    my ($A, $B) = @_;
258	    ($A, $B) = wymum($A, $B);
259	    return $A ^ $B;
260	}
