262	sub convert32BitTo64Bit($) {
263	    my ($v) = @_;
264	    my ($mask1) = 281470681808895;   # 0x0000_ffff_0000_ffff
265	    $v = ($v | ($v << 16)) & $mask1;
266	    my ($mask2) = 71777214294589695; # 0x00ff_00ff_00ff_00ff
267	    return ($v | ($v << 8)) & $mask2;
268	}
269	
270	sub convert16BitTo32Bit($) {
271	    my ($v) = @_;
272	    return ($v | ($v << 8)) & 0x00ff_00ff;
273	}
