275	sub wyhash {
276	    # https://github.com/wangyi-fudan/wyhash
277	    my @chars = @_;
278	    my $charCount = scalar @chars;
279	    my $byteCount = $charCount << 1;
280	    my $charIndex = 0;
281	    my $seed = 0;
282	    my @secret = ( 11562461410679940143, 16646288086500911323, 10285213230658275043, 6384245875588680899 );
283	    my $move1 = (($byteCount >> 3) << 2) >> 1;
284	
285	    $seed ^= wymix($seed ^ $secret[0], $secret[1]);
286	    my $a = 0;
287	    my $b = 0;
288	
289	    local *c2i = sub {
290	        my ($i) = @_;
291	        return ord($chars[$i]);
292	    };
293	
294	    local *wyr8 = sub {
295	        my ($i) = @_;
296	        my $v = c2i($i) | (c2i($i + 1) << 8) | (c2i($i + 2) << 16) | (c2i($i + 3) << 24);
297	        return convert32BitTo64Bit($v);
298	    };
299	
300	    local *wyr4 = sub {
301	        my ($i) = @_;
302	        my $v = c2i($i) | (c2i($i + 1) << 8);
303	        return convert16BitTo32Bit($v);
304	    };
305	
306	    local *wyr2 = sub {
307	        my ($i) = @_;
308	        return c2i($i) << 16;
309	    };
310	
311	    if ($byteCount <= 16) {
312	        if ($byteCount >= 4) {
313	            $a = (wyr4($charIndex) << 32) | wyr4($charIndex + $move1);
314	            $charIndex = $charIndex + $charCount - 2;
315	            $b = (wyr4($charIndex) << 32) | wyr4($charIndex - $move1);
316	        } elsif ($byteCount > 0) {
317	            $a = wyr2($charIndex);
318	            $b = 0;
319	        } else {
320	            $a = $b = 0;
321	        }
322	    } else {
323	        my $i = $byteCount;
324	        if ($i > 48) {
325	            my $see1 = $seed;
326	            my $see2 = $seed;
327	            do {
328	                $seed = wymix(wyr8($charIndex) ^ $secret[1], wyr8($charIndex + 4) ^ $seed);
329	                $see1 = wymix(wyr8($charIndex + 8) ^ $secret[2], wyr8($charIndex + 12) ^ $see1);
330	                $see2 = wymix(wyr8($charIndex + 16) ^ $secret[3], wyr8($charIndex + 20) ^ $see2);
331	                $charIndex += 24;
332	                $i -= 48;
333	            } while ($i > 48);
334	            $seed ^= $see1 ^ $see2;
335	        }
336	        while ($i > 16) {
337	            $seed = wymix(wyr8($charIndex) ^ $secret[1], wyr8($charIndex + 4) ^ $seed);
338	            $i -= 16;
339	            $charIndex += 8;
340	        }
341	        my $move2 = $i >> 1;
342	        $a = wyr8($charIndex + $move2 - 8);
343	        $b = wyr8($charIndex + $move2 - 4);
344	    }
345	    $a ^= $secret[1];
346	    $b ^= $seed;
347	
348	    ($a, $b) = wymum($a, $b);
349	    my $hash = wymix($a ^ $secret[0] ^ $byteCount, $b ^ $secret[1]) & $mask32;
350	
351	    return maskTop8BitsAndAvoidZero($hash);
352	}
