360	sub output() {
361	    if (!$banner) {
362	        $banner = 1;
363	        print "// Automatically generated from $file using $0. DO NOT EDIT!\n";
364	    }
365	
366	    my $nameEntries = "${name}Values";
367	    $nameEntries =~ s/:/_/g;
368	    my $nameIndex = "${name}Index";
369	    $nameIndex =~ s/:/_/g;
370	
371	    print "\n";
372	    print "#include \"JSCBuiltins.h\"\n" if ($includeBuiltin);
373	    print "#include \"Lookup.h\"\n";
374	    print "\n";
375	    print "namespace JSC {\n";
376	    print "\n";
377	
378	    local *generateHashTableHelper = sub {
379	        calcPerfectHashSize();
380	        calcCompactHashSize();
381	
382	        my $hashTableString = "";
383	
384	        if ($compactSize != 0) {
385	            $hashTableString .= "static constinit const struct CompactHashIndex ${nameIndex}\[$compactSize\] = {\n";
386	            for (my $i = 0; $i < $compactSize; $i++) {
387	                my $T = -1;
388	                if (defined($table[$i])) { $T = $table[$i]; }
389	                my $L = -1;
390	                if (defined($links[$i])) { $L = $links[$i]; }
391	                $hashTableString .= "    { $T, $L },\n";
392	            }
393	        } else {
394	            # MSVC dislikes empty arrays.
395	            $hashTableString .= "static constinit const struct CompactHashIndex ${nameIndex}\[1\] = {\n";
396	            $hashTableString .= "    { 0, 0 }\n";
397	        }
398	        $hashTableString .= "};\n";
399	        $hashTableString .= "\n";
400	
401	        my $packedSize = scalar @keys;
402	        if ($packedSize != 0) {
403	            $hashTableString .= "static constinit const struct HashTableValue ${nameEntries}\[$packedSize\] = {\n";
404	        } else {
405	            # MSVC dislikes empty arrays.
406	            $hashTableString .= "static constinit const struct HashTableValue ${nameEntries}\[1\] = {\n";
407	            $hashTableString .= "    { { }, 0, NoIntrinsic, { HashTableValue::End } }\n";
408	        }
409	
410	        my $i = 0;
411	        foreach my $key (@keys) {
412	            my $typeTag = "";
413	            my $firstValue = "";
414	            my $secondValue = "";
415	            my $hasSecondValue = 1;
416	            my $intrinsic = "NoIntrinsic";
417	
418	            if ($values[$i]{"type"} eq "PropertyAttribute::Function") {
419	                $typeTag = "NativeFunction";
420	                $firstValue = $values[$i]{"function"};
421	                $secondValue = $values[$i]{"params"};
422	                $intrinsic = $values[$i]{"intrinsic"};
423	            } elsif ($values[$i]{"type"} eq "PropertyAttribute::BuiltinAccessor") {
424	                $typeTag = "BuiltinAccessor";
425	                $firstValue = $values[$i]{"get"};
426	                $secondValue = $values[$i]{"put"};
427	            } elsif ($values[$i]{"type"} eq "PropertyAttribute::ConstantInteger") {
428	                $typeTag = "Constant";
429	                $firstValue = $values[$i]{"value"};
430	                $hasSecondValue = 0;
431	            } elsif ($values[$i]{"type"} eq "PropertyAttribute::Property") {
432	                $typeTag = "GetterSetter";
433	                $firstValue = $values[$i]{"get"};
434	                $secondValue = $values[$i]{"put"};
435	            } elsif ($values[$i]{"type"} eq "Lexer") {
436	                $typeTag = "Lexer";
437	                $firstValue = $values[$i]{"value"};
438	                $hasSecondValue = 0;
439	            } elsif ($values[$i]{"type"} eq "PropertyAttribute::CellProperty" || $values[$i]{"type"} eq "PropertyAttribute::ClassStructure") {
440	                $typeTag = ($values[$i]{"type"} eq "PropertyAttribute::CellProperty") ? "LazyCellProperty" : "LazyClassStructure";
441	                $values[$i]{"property"} =~ /\A([a-zA-Z0-9_]+)::(.*)\Z/ or die;
442	                $firstValue = "OBJECT_OFFSETOF($1, $2)";
443	                $hasSecondValue = 0;
444	            } elsif ($values[$i]{"type"} eq "PropertyAttribute::PropertyCallback") {
445	                $typeTag = "LazyProperty";
446	                $firstValue = $values[$i]{"cback"};
447	                $hasSecondValue = 0;
448	            }
449	
450	            my $attributes = "PropertyAttribute::" . $attrs[$i];
451	            $attributes =~ s/\|/\|PropertyAttribute::/g;
452	            $attributes = "static_cast<unsigned>(" . $attributes . ")";
453	            if ($values[$i]{"type"} eq "PropertyAttribute::Function" && $firstValue eq "JSBuiltin")  {
454	                $typeTag = "BuiltinGenerator";
455	                my $tableHead = $name;
456	                $tableHead =~ s/Table$//;
457	                $hashTableString .= "   { \"$key\"_s, (($attributes) & ~PropertyAttribute::Function) | PropertyAttribute::Builtin, $intrinsic, { HashTableValue::" . $typeTag . "Type, " . $tableHead . ucfirst($key) . "CodeGenerator, $secondValue } },\n";
458	            }
459	            else {
460	                $hashTableString .= "   { \"$key\"_s, $attributes, $intrinsic, { HashTableValue::" . $typeTag . "Type, $firstValue" . ($hasSecondValue ? ", " . $secondValue : "") . " } },\n";
461	            }
462	            $i++;
463	        }
464	        $hashTableString .= "};\n";
465	        $hashTableString .= "\n";
466	        $hashTableString .= "static constinit const struct HashTable $name =\n";
467	        $hashTableString .= "    \{ $packedSize, $compactHashSizeMask, $hasSetter, nullptr, $nameEntries, $nameIndex \};\n";
468	        $hashTableString .= "\n";
469	
470	        @table = ();
471	        @links = ();
472	        return $hashTableString;
473	    };
474	
475	    print generateHashTableHelper();
476	
477	    print "} // namespace JSC\n";
478	}
